app/routes/user/page.py<pre><code>from reroute import RouteBase
from reroute.decorators import cache, rate_limit

class UserRoutes(RouteBase):
    tag = "Users"

    @cache(duration=60)
    def get(self):
        return {"users": ["Alice", "Bob"]}

    @rate_limit("5/min")
    def post(self):
        return {"message": "User created"}
